mapper.select:
SELECT id, owner_user_id, name, description, created_at, updated_at
FROM teams
WHERE owner_user_id = #{ownerUserId} AND name = #{name}

mapper.update:
UPDATE teams
SET name = #{name},
    description = #{description}
WHERE id = #{id}
  AND owner_user_id = #{ownerUserId}

mapper.delete:
DELETE FROM teams
WHERE id = #{id}
  AND owner_user_id = #{ownerUserId}

mapper.update:
UPDATE team_members
SET status = 'REJECTED',
    rejected_at = NOW()
WHERE id = #{id}
  AND user_id = #{userId}
  AND status = 'INVITED'

UPDATE team_members
SET status = 'CANCELLED',
    cancelled_at = NOW()
WHERE id = #{id}
  AND team_id = #{teamId}
  AND status = 'INVITED'

